from ariadne import QueryType, make_executable_schema, gql, load_schema_from_path
from ariadne.asgi import GraphQL
from fastapi import FastAPI, Request
from starlette.middleware.base import BaseHTTPMiddleware

type_defs = gql("""
    type User {
        username: String!
        bio: String
        email: String
        phone: String
        address: String
    }

    type Post {
        title: String!
        content: String!
        author: User!
    }

    type Query {
        userProfile(username: String!): User
    }
""")

query = QueryType()

users_db = {
    "john_doe": {
        "username": "john_doe",
        "bio": "Software Developer",
        "email": "john@example.com",
        "phone": "123-456-7890",
        "address": "123 Main St"
    }
}

def get_current_user(request: Request):
    # Simulate authentication
    return users_db.get("john_doe")

class AuthMiddleware(BaseHTTPMiddleware):
    async def dispatch(self, request: Request, call_next):
        request.state.current_user = get_current_user(request)
        response = await call_next(request)
        return response

@query.field("userProfile")
def resolve_user_profile(_, info, username):
    current_user = info.context["request"].state.current_user
    if current_user and current_user["username"] == username:
        return current_user
    user = users_db.get(username)
    if user:
        return {
            "username": user["username"],
            "bio": user["bio"],
            "email": None,
            "phone": None,
            "address": None
        }
    return None

schema = make_executable_schema(type_defs, query)

app = FastAPI()
app.add_middleware(AuthMiddleware)
app.add_route("/graphql", GraphQL(schema, context_value=lambda request: {"request": request}))